import com.npci.upi.dto.ReqMandate;

public class ReqMandateValidator {

    public static String validate(ReqMandate req) {
        if (req.getHead() == null) {
            return "HEAD_MISSING";
        }
        if (req.getHead().getVer() == null) {
            return "VER_MISSING";
        }
        if (req.getHead().getTs() == null) {
            return "TS_MISSING";
        }
        if (req.getHead().getOrgid() == null) {
